        private static void AddScheme(string family, string type, int k, (int R, int G, int B)[] colors)
        {
            for (int i = 0; i < colors.Length; i++)
            {
                string name = $"{family}_{k}_{type}_{i + 1}";
                Map[name] = Color.FromRgb((byte)colors[i].R, (byte)colors[i].G, (byte)colors[i].B);
            }
        }

        public static bool TryGetColor(string name, out Color color)
        {
            return Map.TryGetValue(name, out color);
        }
    }
